'use client';

import { useState, useEffect } from 'react';
import api from '@/lib/api';
import { useAuth } from '@/contexts/AuthContext';
import { Calendar, Search, Check, X, ShieldAlert, CheckCircle2, Clock, CalendarDays, ExternalLink } from 'lucide-react';
import { toast } from 'react-hot-toast';

export default function ReviewEvents() {
    const { user } = useAuth();
    const [events, setEvents] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState('pending');

    const fetchEvents = async () => {
        setLoading(true);
        try {
            const { data } = await api.get('/council/events', {
                params: { status: statusFilter, limit: 50 },
                withCredentials: true
            });
            setEvents(data.items);
        } catch (error) {
            toast.error('Failed to fetch events');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchEvents();
    }, [statusFilter]);

    const handleAction = async (id: string, action: 'approved' | 'rejected' | 'completed') => {
        try {
            if (action === 'approved') {
                await api.put(`/council/events/${id}/approve`, {}, { withCredentials: true });
            } else {
                await api.put(`/council/events/${id}`, { status: action }, { withCredentials: true });
            }

            toast.success(`Event ${action} successfully`);
            fetchEvents(); // refresh
        } catch (error) {
            toast.error(`Failed to update event`);
        }
    };

    if (!user?.roles?.some((r: string) => ['admin', 'council_admin'].includes(r))) {
        return (
            <div className="flex flex-col items-center justify-center p-8 min-h-screen">
                <ShieldAlert className="w-16 h-16 text-red-500 mb-4" />
                <h1 className="text-2xl font-bold text-white mb-2">Access Denied</h1>
            </div>
        );
    }

    return (
        <div className="p-6 md:p-8 w-full max-w-7xl mx-auto min-h-screen">
            <header className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-white tracking-tight mb-2 flex items-center gap-3">
                        <Calendar className="w-8 h-8 text-orange-500" />
                        Event Management
                    </h1>
                    <p className="text-white/60">
                        Review, approve, and manage registered events across all clubs and councils.
                    </p>
                </div>

                <div className="flex bg-[#111] p-1 rounded-xl border border-white/10">
                    {['pending', 'approved', 'rejected', 'completed'].map(status => (
                        <button
                            key={status}
                            onClick={() => setStatusFilter(status)}
                            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors capitalize ${statusFilter === status
                                    ? 'bg-white/10 text-white'
                                    : 'text-white/40 hover:text-white/80 hover:bg-white/5'
                                }`}
                        >
                            {status}
                        </button>
                    ))}
                </div>
            </header>

            <div className="space-y-4">
                {loading ? (
                    <div className="flex justify-center p-12">
                        <div className="w-8 h-8 rounded-full border-2 border-orange-500/20 border-t-orange-500 animate-spin" />
                    </div>
                ) : events.length === 0 ? (
                    <div className="text-center py-20 bg-[#111] border border-white/5 rounded-2xl">
                        <CalendarDays className="w-12 h-12 text-white/20 mx-auto mb-4" />
                        <h3 className="text-lg font-medium text-white mb-1">Queue Empty</h3>
                        <p className="text-white/50">No {statusFilter} events found.</p>
                    </div>
                ) : (
                    events.map(event => (
                        <div key={event._id} className="bg-[#111] border border-white/5 rounded-2xl p-6 transition-all hover:border-white/10">
                            <div className="flex flex-col md:flex-row gap-6 items-start justify-between">
                                <div className="flex-1 space-y-4">
                                    <div>
                                        <div className="flex items-center gap-3 mb-2">
                                            <h3 className="text-lg font-bold text-white">{event.title}</h3>
                                            <span className="px-2.5 py-1 rounded-full text-xs font-medium bg-white/5 text-white/70 capitalize border border-white/10">
                                                {event.category}
                                            </span>
                                            {event.isPublic && (
                                                <span className="px-2.5 py-1 rounded-full text-xs font-medium bg-indigo-500/10 text-indigo-400 capitalize border border-indigo-500/20">
                                                    Public
                                                </span>
                                            )}
                                        </div>
                                        <p className="text-white/60 text-sm flex gap-3 flex-wrap">
                                            <span className="flex items-center gap-1"><CalendarDays className="w-3 h-3" /> {new Date(event.date).toLocaleDateString()}</span>
                                            {event.time && <span>• {event.time}</span>}
                                            {event.clubId?.name && <span>• <strong>Club:</strong> {event.clubId.name}</span>}
                                            <span>• <strong>Organizer:</strong> {event.organizerId?.name || 'Unknown'}</span>
                                        </p>
                                    </div>

                                    {event.description && (
                                        <p className="text-white/70 text-sm bg-white/5 p-3 rounded-xl border border-white/5">
                                            {event.description}
                                        </p>
                                    )}

                                    {statusFilter === 'approved' && (
                                        <a
                                            href={`/council/events/${event._id}`}
                                            target="_blank"
                                            className="inline-flex items-center gap-2 text-sm text-white/50 hover:text-white transition-colors px-3 py-1.5 rounded-lg hover:bg-white/5 mt-2"
                                        >
                                            <ExternalLink className="w-4 h-4" /> View Live Event Page
                                        </a>
                                    )}
                                </div>

                                <div className="shrink-0 flex flex-col gap-2 w-full md:w-auto md:min-w-[160px]">
                                    {statusFilter === 'pending' && (
                                        <>
                                            <button
                                                onClick={() => handleAction(event._id, 'approved')}
                                                className="w-full flex items-center justify-center gap-2 py-2.5 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 text-sm font-medium rounded-xl transition-colors border border-emerald-500/20"
                                            >
                                                <Check className="w-4 h-4" /> Approve
                                            </button>
                                            <button
                                                onClick={() => handleAction(event._id, 'rejected')}
                                                className="w-full flex items-center justify-center gap-2 py-2.5 bg-red-500/10 hover:bg-red-500/20 text-red-400 text-sm font-medium rounded-xl transition-colors border border-red-500/20"
                                            >
                                                <X className="w-4 h-4" /> Reject
                                            </button>
                                        </>
                                    )}

                                    {statusFilter === 'approved' && (
                                        <button
                                            onClick={() => handleAction(event._id, 'completed')}
                                            className="w-full flex items-center justify-center gap-2 py-2.5 bg-blue-500/10 hover:bg-blue-500/20 text-blue-400 text-sm font-medium rounded-xl transition-colors border border-blue-500/20"
                                        >
                                            <CheckCircle2 className="w-4 h-4" /> Mark Completed
                                        </button>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
}

'use client';

import { useAuth } from '@/contexts/AuthContext';
import { useRouter, usePathname } from 'next/navigation';
import { useEffect } from 'react';
import Link from 'next/link';
import {
    LayoutDashboard,
    Users,
    BookOpen,
    Calendar,
    MessageSquare,
    LogOut,
    Menu,
    X,
    Shield,
    Terminal
} from 'lucide-react';
import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const ADMIN_ROLES = ['admin', 'council_admin', 'voice_admin', 'learn_admin', 'coding_ta'];

export default function AdminLayout({ children }: { children: React.ReactNode }) {
    const { user, loading, logout } = useAuth();
    const router = useRouter();
    const pathname = usePathname();
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    useEffect(() => {
        if (!loading) {
            if (!user) {
                router.push('/auth/login?redirect=/admin');
            } else if (!user.roles.some((r: string) => ADMIN_ROLES.includes(r))) {
                router.push('/');
            }
        }
    }, [user, loading, router]);

    if (loading || !user || !user.roles.some((r: string) => ADMIN_ROLES.includes(r))) {
        return (
            <div className="min-h-screen bg-[#0a0a0a] flex items-center justify-center">
                <div className="w-8 h-8 rounded-full border-2 border-white/20 border-t-white animate-spin" />
            </div>
        );
    }

    const navigation = [
        { name: 'Overview', href: '/admin', icon: LayoutDashboard, roles: ['admin', 'council_admin', 'voice_admin', 'learn_admin'] },
        { name: 'Users', href: '/admin/users', icon: Users, roles: ['admin'] },
        { name: 'Learn (Papers)', href: '/admin/learn/papers', icon: BookOpen, roles: ['admin', 'learn_admin'] },
        { name: 'Council (Events)', href: '/admin/council/events', icon: Calendar, roles: ['admin', 'council_admin'] },
        { name: 'Voice (Complaints)', href: '/admin/voice/complaints', icon: MessageSquare, roles: ['admin', 'voice_admin'] },
        { name: 'Learn (Coding Hour)', href: '/admin/learn/coding-hour', icon: Terminal, roles: ['admin', 'learn_admin', 'coding_ta'] },
    ];

    const authorizedNavigation = navigation.filter(item =>
        item.roles.some(role => user.roles.includes(role))
    );

    const Sidebar = () => (
        <div className="flex flex-col h-full bg-[#0f0f0f] border-r border-white/10 w-64 md:w-72">
            {/* Header */}
            <div className="h-16 flex items-center px-6 border-b border-white/10 shrink-0">
                <div className="flex gap-2 items-center text-white font-bold text-lg cursor-pointer" onClick={() => router.push('/')}>
                    <Shield className="w-5 h-5 text-indigo-500" />
                    <span>Nexus Admin</span>
                </div>
            </div>

            {/* Navigation */}
            <div className="flex-1 overflow-y-auto py-4 px-3 space-y-1">
                {authorizedNavigation.map((item) => {
                    const isActive = pathname === item.href;
                    const Icon = item.icon;
                    return (
                        <Link
                            key={item.name}
                            href={item.href}
                            onClick={() => setIsMobileMenuOpen(false)}
                            className={`flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-colors ${isActive
                                ? 'bg-indigo-500/15 text-indigo-400'
                                : 'text-white/60 hover:text-white hover:bg-white/5'
                                }`}
                        >
                            <Icon className={`w-4 h-4 ${isActive ? 'text-indigo-400' : 'text-white/40'}`} />
                            {item.name}
                        </Link>
                    );
                })}
            </div>

            {/* Footer */}
            <div className="p-4 border-t border-white/10 shrink-0">
                <div className="flex items-center gap-3 mb-4 px-2">
                    <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-indigo-500 to-purple-500 flex items-center justify-center text-white font-bold text-xs ring-2 ring-white/10">
                        {user.name.charAt(0).toUpperCase()}
                    </div>
                    <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-white truncate">{user.name}</p>
                        <p className="text-xs text-white/50 truncate capitalize">
                            {user.roles.find((r: string) => ADMIN_ROLES.includes(r))?.replace('_', ' ')}
                        </p>
                    </div>
                </div>
                <button
                    onClick={() => logout()}
                    className="w-full flex items-center gap-3 px-3 py-2 rounded-xl text-sm font-medium text-red-400 hover:bg-red-500/10 transition-colors"
                >
                    <LogOut className="w-4 h-4" />
                    Sign Out
                </button>
            </div>
        </div>
    );

    return (
        <div className="min-h-screen bg-[#0a0a0a] flex flex-col md:flex-row font-sans">
            {/* Mobile Header */}
            <div className="md:hidden h-16 bg-[#0f0f0f] border-b border-white/10 flex items-center justify-between px-4 sticky top-0 z-50">
                <div className="flex gap-2 items-center text-white font-bold" onClick={() => router.push('/')}>
                    <Shield className="w-5 h-5 text-indigo-500" />
                    <span>Nexus Admin</span>
                </div>
                <button
                    onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                    className="p-2 text-white/70 hover:text-white hover:bg-white/10 rounded-lg transition-colors"
                >
                    {isMobileMenuOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
                </button>
            </div>

            {/* Mobile Sidebar Overlay */}
            <AnimatePresence>
                {isMobileMenuOpen && (
                    <>
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setIsMobileMenuOpen(false)}
                            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-40 md:hidden"
                        />
                        <motion.div
                            initial={{ x: '-100%' }}
                            animate={{ x: 0 }}
                            exit={{ x: '-100%' }}
                            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                            className="fixed inset-y-0 left-0 z-50 md:hidden"
                        >
                            <Sidebar />
                        </motion.div>
                    </>
                )}
            </AnimatePresence>

            {/* Desktop Sidebar */}
            <div className="hidden md:block sticky top-0 h-screen shrink-0">
                <Sidebar />
            </div>

            {/* Main Content */}
            <div className="flex-1 w-full max-w-7xl mx-auto overflow-hidden">
                {children}
            </div>
        </div>
    );
}

'use client';

import React, { useState, useEffect, useRef } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/contexts/AuthContext';
import axios from 'axios';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Plus, X, Loader2, Code, Calendar,
    Terminal, Trash2, Edit,
    LogOut, ChevronDown, ChevronUp,
    Megaphone, FileText, Upload, ArrowLeft
} from 'lucide-react';
import Link from 'next/link';

const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';

interface Course {
    _id: string; // MongoDB uses _id
    code: string;
    name: string;
}

interface Question {
    _id?: string;
    order: number;
    title: string;
    question: string;
    codeSnippets: { [key: string]: string };
    explanation: string;
    mediaLink?: string;
}

interface Contest {
    _id: string;
    courseId: string | Course;
    date: string;
    title?: string;
    description?: string;
    questions: Question[];
}

interface Announcement {
    _id: string;
    courseId?: string | Course | null;
    title: string;
    content: string;
    attachmentUrl?: string;
    createdAt: string;
}

const SUPPORTED_LANGUAGES = ['c', 'python', 'cpp', 'java', 'javascript'];

export default function CodingHourAdmin() {
    const { user, token, logout } = useAuth();
    const router = useRouter();
    const [courses, setCourses] = useState<Course[]>([]);
    const [contests, setContests] = useState<Contest[]>([]);
    const [loading, setLoading] = useState(true);
    const [actionLoading, setActionLoading] = useState(false);
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [expandedQuestion, setExpandedQuestion] = useState<number | null>(0);
    const [editingContestId, setEditingContestId] = useState<string | null>(null);
    const [showAnnouncementModal, setShowAnnouncementModal] = useState(false);
    const [announcements, setAnnouncements] = useState<Announcement[]>([]);

    // Announcement Form
    const [announcementForm, setAnnouncementForm] = useState({
        title: '',
        content: '',
        courseId: '',
        attachmentUrl: '' // Simplified for now since Nexus backend expects a string URL
    });

    // Matrix Rain Ref
    const canvasRef = useRef<HTMLCanvasElement>(null);

    // Form state for multi-question contest
    const [contestForm, setContestForm] = useState({
        courseId: '',
        date: '',
        title: '',
        description: ''
    });

    const [questions, setQuestions] = useState<Question[]>([{
        order: 1,
        title: '',
        question: '',
        codeSnippets: { python: '' },
        explanation: '',
        mediaLink: ''
    }]);

    // Matrix Rain Effect
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;

        const matrix = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789@#$%^&*()_+-=[]{}|;:,.<>?";
        const fontSize = 14;
        const columns = canvas.width / fontSize;
        const drops: number[] = [];

        for (let x = 0; x < columns; x++) {
            drops[x] = 1;
        }

        const draw = () => {
            ctx.fillStyle = 'rgba(0, 0, 0, 0.04)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            ctx.fillStyle = '#00ff41'; // Matrix Green
            ctx.font = fontSize + 'px monospace';

            for (let i = 0; i < drops.length; i++) {
                const text = matrix[Math.floor(Math.random() * matrix.length)];
                ctx.fillText(text, i * fontSize, drops[i] * fontSize);

                if (drops[i] * fontSize > canvas.height && Math.random() > 0.975) {
                    drops[i] = 0;
                }
                drops[i]++;
            }
        };

        const interval = setInterval(draw, 35);

        const handleResize = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        };

        window.addEventListener('resize', handleResize);

        return () => {
            clearInterval(interval);
            window.removeEventListener('resize', handleResize);
        };
    }, []);

    useEffect(() => {
        // Redirect if not a host
        if (!user || (!user.roles.includes('admin') && !user.roles.includes('coding_ta') && !user.roles.includes('learn_admin'))) {
            router.push('/');
            return;
        }
        if (token) {
            fetchData();
        }
    }, [user, router, token]);

    const fetchData = async () => {
        setLoading(true);
        try {
            const [coursesRes, contestsRes, annRes] = await Promise.all([
                axios.get(`${API_BASE_URL}/learn/courses`),
                axios.get(`${API_BASE_URL}/learn/contests`, { headers: { Authorization: `Bearer ${token}` } }),
                axios.get(`${API_BASE_URL}/learn/announcements`, { headers: { Authorization: `Bearer ${token}` } })
            ]);

            let coursesData = coursesRes.data;

            // Optional: If user is strictly Coding TA, filter courses like legacy
            // Taking all courses for now or filtering only coding:
            coursesData = coursesData.filter((c: Course) =>
                c.code.includes('CODING') || c.name.toLowerCase().includes('coding')
            );

            setCourses(coursesData);
            setContests(contestsRes.data);
            setAnnouncements(annRes.data);
        } catch (error) {
            console.error('Failed to fetch data:', error);
        } finally {
            setLoading(false);
        }
    };

    const addQuestion = () => {
        setQuestions([...questions, {
            order: questions.length + 1,
            title: '',
            question: '',
            codeSnippets: { python: '' },
            explanation: '',
            mediaLink: ''
        }]);
        setExpandedQuestion(questions.length);
    };

    const removeQuestion = (index: number) => {
        if (questions.length === 1) {
            alert('Contest must have at least one question');
            return;
        }
        const newQuestions = questions.filter((_, i) => i !== index);
        newQuestions.forEach((q, i) => q.order = i + 1);
        setQuestions(newQuestions);
        if (expandedQuestion === index) {
            setExpandedQuestion(0);
        }
    };

    const updateQuestion = (index: number, field: keyof Question, value: any) => {
        const newQuestions = [...questions];
        newQuestions[index] = { ...newQuestions[index], [field]: value };
        setQuestions(newQuestions);
    };

    const toggleLanguage = (questionIndex: number, lang: string) => {
        const newQuestions = [...questions];
        const snippets = { ...newQuestions[questionIndex].codeSnippets };

        if (snippets[lang] !== undefined) {
            if (Object.keys(snippets).length === 1) {
                alert('At least one language must be selected');
                return;
            }
            delete snippets[lang];
        } else {
            snippets[lang] = '';
        }

        newQuestions[questionIndex].codeSnippets = snippets;
        setQuestions(newQuestions);
    };

    const updateCodeSnippet = (questionIndex: number, lang: string, code: string) => {
        const newQuestions = [...questions];
        newQuestions[questionIndex].codeSnippets[lang] = code;
        setQuestions(newQuestions);
    };

    const handleEdit = (contest: Contest) => {
        setEditingContestId(contest._id);
        setContestForm({
            courseId: typeof contest.courseId === 'object' ? contest.courseId._id : contest.courseId,
            date: contest.date,
            title: contest.title || '',
            description: contest.description || ''
        });

        // Deep copy questions
        setQuestions(contest.questions.map(q => ({
            ...q,
            codeSnippets: { ...q.codeSnippets }
        })));

        setShowCreateModal(true);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setActionLoading(true);

        try {
            const selectedCourseId = contestForm.courseId;
            const selectedCourse = courses.find(c => c._id === selectedCourseId);
            const isCodingHourC = selectedCourse?.name === 'Coding Hour - C' || selectedCourse?.code === 'CODING_C';

            for (let i = 0; i < questions.length; i++) {
                const q = questions[i];
                if (isCodingHourC) {
                    if (!q.codeSnippets['c'] || q.codeSnippets['c'].trim() === '') {
                        alert(`Question ${i + 1} must have C code snippet (Mandatory for Coding Hour - C).`);
                        setActionLoading(false);
                        return;
                    }
                } else {
                    if (Object.keys(q.codeSnippets).length === 0 || Object.values(q.codeSnippets).every(val => !val || val.trim() === '')) {
                        alert(`Question ${i + 1} must have at least one code snippet.`);
                        setActionLoading(false);
                        return;
                    }
                }
            }

            const contestData = {
                courseId: contestForm.courseId,
                date: contestForm.date,
                title: contestForm.title || `${contestForm.date} Challenge`,
                description: contestForm.description || undefined,
                questions: questions
            };

            if (editingContestId) {
                await axios.put(`${API_BASE_URL}/learn/contests/${editingContestId}`, contestData, {
                    headers: { Authorization: `Bearer ${token}` }
                });
            } else {
                await axios.post(`${API_BASE_URL}/learn/contests`, contestData, {
                    headers: { Authorization: `Bearer ${token}` }
                });
            }

            setShowCreateModal(false);
            resetForm();
            fetchData();
        } catch (error: any) {
            console.error('Submit error:', error);
            alert(error.response?.data?.error || 'Failed to save contest');
        } finally {
            setActionLoading(false);
        }
    };

    const handleAnnouncementSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setActionLoading(true);

        try {
            await axios.post(`${API_BASE_URL}/learn/announcements`, {
                title: announcementForm.title,
                content: announcementForm.content,
                courseId: announcementForm.courseId || undefined,
                attachmentUrl: announcementForm.attachmentUrl || undefined
            }, {
                headers: { Authorization: `Bearer ${token}` }
            });

            setShowAnnouncementModal(false);
            setAnnouncementForm({ title: '', content: '', courseId: '', attachmentUrl: '' });
            fetchData();
        } catch (error: any) {
            console.error('Announcement submit error:', error);
            alert(error.response?.data?.error || 'Failed to post announcement');
        } finally {
            setActionLoading(false);
        }
    };

    const handleDeleteAnnouncement = async (id: string) => {
        if (!window.confirm('Are you sure you want to delete this announcement?')) return;
        try {
            await axios.delete(`${API_BASE_URL}/learn/announcements/${id}`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setAnnouncements(prev => prev.filter(a => a._id !== id));
        } catch (error) {
            alert('Failed to delete announcement');
        }
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm('Are you sure you want to delete this contest?')) return;
        try {
            await axios.delete(`${API_BASE_URL}/learn/contests/${id}`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setContests(prev => prev.filter(c => c._id !== id));
        } catch (error) {
            alert('Failed to delete contest');
        }
    };

    const resetForm = () => {
        setContestForm({ courseId: '', date: '', title: '', description: '' });
        setQuestions([{
            order: 1, title: '', question: '', codeSnippets: { python: '' }, explanation: '', mediaLink: ''
        }]);
        setExpandedQuestion(0);
        setEditingContestId(null);
    };

    if (loading && contests.length === 0) {
        return (
            <div className="min-h-screen bg-black flex flex-col items-center justify-center gap-4">
                <Loader2 className="animate-spin text-green-500 w-12 h-12" />
                <p className="text-green-400 font-mono text-sm animate-pulse">Wait... Accessing System...</p>
            </div>
        );
    }

    return (
        <div className="min-h-screen relative bg-black text-gray-200 font-sans overflow-hidden">
            <canvas ref={canvasRef} className="fixed top-0 left-0 w-full h-full opacity-20 pointer-events-none z-0" />

            {/* Header */}
            <motion.div
                initial={{ y: -20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                className="relative z-10 bg-black/40 backdrop-blur-md border-b border-green-500/30 shadow-lg shadow-green-900/20"
            >
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    <div className="flex justify-between items-center h-16">
                        <div className="flex items-center gap-4">
                            <Link href="/admin" className="text-gray-400 hover:text-white transition-colors">
                                <ArrowLeft className="w-5 h-5" />
                            </Link>
                            <div>
                                <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-green-400 to-emerald-400">
                                    Host Command Center
                                </h1>
                                <p className="text-xs text-green-500/70 font-mono">system.role = 'coding_ta'</p>
                            </div>
                        </div>
                        <div className="flex items-center gap-4">
                            <div className="hidden md:flex items-center gap-2 px-3 py-1.5 rounded-full bg-green-900/20 border border-green-500/30">
                                <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
                                <span className="text-xs font-mono text-green-400">SYSTEM ONLINE</span>
                            </div>
                        </div>
                    </div>
                </div>
            </motion.div>

            {/* Main Content */}
            <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
                    <div>
                        <h2 className="text-3xl font-bold text-white mb-2 flex items-center gap-3">
                            <Terminal className="text-green-500 w-8 h-8" />
                            Active Contests
                        </h2>
                        <p className="text-gray-400">Manage weekly coding problems for students.</p>
                    </div>
                    <div className="flex-1 flex justify-end gap-3 self-end md:self-auto">
                        <button
                            onClick={() => setShowAnnouncementModal(true)}
                            className="px-4 py-2 bg-blue-600/20 text-blue-400 border border-blue-500/30 rounded-lg hover:bg-blue-600/30 transition-all flex items-center gap-2 font-medium"
                        >
                            <Megaphone size={18} />
                            Announce
                        </button>
                        <button
                            onClick={() => setShowCreateModal(true)}
                            className="px-4 py-2 bg-green-600 hover:bg-green-500 text-white rounded-lg shadow-lg shadow-green-900/40 transition-all flex items-center gap-2 font-medium"
                        >
                            <Plus size={18} />
                            New Contest
                        </button>
                    </div>
                </div>

                <div className="grid gap-6 grid-cols-1 md:grid-cols-2 xl:grid-cols-3">
                    {contests.map((contest, index) => (
                        <motion.div
                            key={contest._id}
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: index * 0.05 }}
                            className="group bg-gray-900/60 backdrop-blur-sm border border-green-500/20 rounded-xl p-6 hover:border-green-500/50 hover:shadow-[0_0_20px_rgba(34,197,94,0.1)] transition-all duration-300"
                        >
                            <div className="flex justify-between items-start mb-4">
                                <div className="flex items-center gap-2">
                                    <Calendar className="w-4 h-4 text-green-500" />
                                    <span className="font-mono text-green-400 font-bold">{contest.date}</span>
                                </div>
                                <div className="flex gap-2">
                                    <button
                                        onClick={() => handleEdit(contest)}
                                        className="p-1.5 text-gray-500 hover:text-green-400 transition-colors bg-gray-800 rounded-md"
                                        title="Edit"
                                    >
                                        <Edit size={16} />
                                    </button>
                                    <button
                                        onClick={() => handleDelete(contest._id)}
                                        className="p-1.5 text-gray-500 hover:text-red-400 transition-colors bg-gray-800 rounded-md"
                                        title="Delete"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>

                            <h3 className="text-lg font-bold text-white mb-2 line-clamp-1">
                                {contest.title || contest.date}
                            </h3>

                            <div className="mb-4">
                                <div className="text-sm text-gray-400 mb-2">
                                    {contest.questions?.length || 0} Question{(contest.questions?.length !== 1) ? 's' : ''}
                                </div>
                                {contest.questions?.slice(0, 2).map((q, i) => (
                                    <div key={i} className="text-xs text-gray-500 mb-1 flex items-center gap-2">
                                        <Code className="w-3 h-3 text-gray-600" />
                                        <span className="line-clamp-1">{q.title}</span>
                                    </div>
                                ))}
                            </div>

                            <div className="text-xs text-gray-500 border-t border-white/5 pt-4">
                                ID: {contest._id.substring(0, 8)}...
                            </div>
                        </motion.div>
                    ))}
                </div>

                {/* Announcements */}
                {announcements.length > 0 && (
                    <div className="mt-12 mb-12">
                        <h3 className="text-xl font-bold text-white flex items-center gap-2 mb-6">
                            <Megaphone className="text-blue-500" />
                            Active Announcements
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                            {announcements.map((ann) => (
                                <div key={ann._id} className="bg-gray-800/50 border border-blue-500/20 rounded-xl p-6 relative">
                                    <div className="flex justify-between items-start mb-2">
                                        <h4 className="text-lg font-bold text-white">{ann.title}</h4>
                                        <button onClick={() => handleDeleteAnnouncement(ann._id)} className="text-gray-500 hover:text-red-400">
                                            <Trash2 size={16} />
                                        </button>
                                    </div>
                                    <p className="text-gray-400 text-sm mb-4 line-clamp-3">{ann.content}</p>
                                    {ann.attachmentUrl && (
                                        <a href={ann.attachmentUrl} target="_blank" rel="noopener noreferrer" className="flex items-center gap-2 text-xs text-blue-400 bg-blue-900/20 px-3 py-1.5 rounded-lg w-fit hover:bg-blue-900/40">
                                            <FileText size={14} /> View Link
                                        </a>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Create Modal */}
                <AnimatePresence>
                    {showCreateModal && (
                        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-50 p-4 overflow-y-auto">
                            <motion.div
                                initial={{ scale: 0.95, y: 20 }}
                                animate={{ scale: 1, y: 0 }}
                                exit={{ scale: 0.95, y: 20 }}
                                className="bg-gray-900 border border-green-500/30 rounded-2xl max-w-4xl w-full max-h-[90vh] overflow-y-auto scrollbar-thin scrollbar-thumb-gray-700 shadow-2xl"
                            >
                                <div className="sticky top-0 bg-gray-900/95 backdrop-blur border-b border-green-500/20 p-6 flex justify-between items-center z-10">
                                    <h2 className="text-2xl font-bold text-white flex items-center gap-3">
                                        <Terminal className="text-green-500" />
                                        {editingContestId ? 'Edit Contest' : 'Initialize Contest'}
                                    </h2>
                                    <button onClick={() => { setShowCreateModal(false); resetForm(); }} className="text-gray-400 hover:text-white">
                                        <X size={24} />
                                    </button>
                                </div>

                                <form onSubmit={handleSubmit} className="p-6 space-y-6">
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <div>
                                            <label className="block text-sm font-medium text-green-400 mb-2 font-mono">TARGET_COURSE</label>
                                            <select
                                                value={contestForm.courseId}
                                                onChange={(e) => setContestForm({ ...contestForm, courseId: e.target.value })}
                                                className="w-full px-4 py-3 bg-black/40 border border-green-500/20 rounded-lg text-white focus:outline-none focus:border-green-500 font-mono"
                                                required
                                            >
                                                <option value="">SELECT COURSE...</option>
                                                {courses.map((c) => (
                                                    <option key={c._id} value={c._id}>[{c.code}] {c.name}</option>
                                                ))}
                                            </select>
                                        </div>
                                        <div>
                                            <label className="block text-sm font-medium text-green-400 mb-2 font-mono">EXECUTION_DATE</label>
                                            <input
                                                type="text"
                                                value={contestForm.date}
                                                onChange={(e) => setContestForm({ ...contestForm, date: e.target.value })}
                                                className="w-full px-4 py-3 bg-black/40 border border-green-500/20 rounded-lg text-white focus:outline-none focus:border-green-500 font-mono"
                                                placeholder="Week 1 - Day 1"
                                                required
                                            />
                                        </div>
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-green-400 mb-2 font-mono">CONTEST_TITLE (Optional)</label>
                                        <input
                                            type="text"
                                            value={contestForm.title}
                                            onChange={(e) => setContestForm({ ...contestForm, title: e.target.value })}
                                            className="w-full px-4 py-3 bg-black/40 border border-green-500/20 rounded-lg text-white focus:outline-none focus:border-green-500 font-mono"
                                            placeholder="Introduction to C"
                                        />
                                    </div>

                                    {/* Questions List */}
                                    <div className="border-t border-green-500/20 pt-6">
                                        <div className="flex justify-between items-center mb-4">
                                            <h3 className="text-xl font-bold text-white flex items-center gap-2">
                                                <Code className="text-green-500" />
                                                Questions ({questions.length})
                                            </h3>
                                            <button type="button" onClick={addQuestion} className="px-4 py-2 bg-green-600/20 text-green-400 rounded-lg border border-green-500/30 flex items-center gap-2 text-sm">
                                                <Plus size={16} /> Add Question
                                            </button>
                                        </div>

                                        <div className="space-y-4">
                                            {questions.map((q, qIndex) => (
                                                <div key={qIndex} className="border border-green-500/20 rounded-lg bg-black/20 overflow-hidden">
                                                    <div className="flex justify-between items-center p-4 bg-green-900/10 cursor-pointer" onClick={() => setExpandedQuestion(expandedQuestion === qIndex ? null : qIndex)}>
                                                        <div className="flex items-center gap-3">
                                                            <span className="text-green-400 font-mono font-bold">Q{qIndex + 1}</span>
                                                            <span className="text-white text-sm">{q.title || 'Untitled'}</span>
                                                        </div>
                                                        <div className="flex items-center gap-2">
                                                            {questions.length > 1 && (
                                                                <button type="button" onClick={(e) => { e.stopPropagation(); removeQuestion(qIndex); }} className="p-1.5 text-gray-500 hover:text-red-400">
                                                                    <Trash2 size={16} />
                                                                </button>
                                                            )}
                                                            {expandedQuestion === qIndex ? <ChevronUp className="text-green-400" size={16} /> : <ChevronDown className="text-green-400" size={16} />}
                                                        </div>
                                                    </div>

                                                    {expandedQuestion === qIndex && (
                                                        <div className="p-4 space-y-4 border-t border-green-500/10">
                                                            <input
                                                                type="text"
                                                                value={q.title}
                                                                onChange={(e) => updateQuestion(qIndex, 'title', e.target.value)}
                                                                className="w-full px-4 py-2 bg-black/40 border border-green-500/20 rounded-lg text-white text-sm focus:border-green-500"
                                                                placeholder="Question Title"
                                                                required
                                                            />
                                                            <textarea
                                                                value={q.question}
                                                                onChange={(e) => updateQuestion(qIndex, 'question', e.target.value)}
                                                                className="w-full px-4 py-2 bg-black/40 border border-green-500/20 rounded-lg text-white text-sm min-h-[100px] focus:border-green-500"
                                                                placeholder="Problem Statement"
                                                                required
                                                            />

                                                            {/* Languages */}
                                                            <div>
                                                                <label className="block text-xs text-green-400 mb-2 uppercase tracking-wider">Languages</label>
                                                                <div className="flex flex-wrap gap-2">
                                                                    {SUPPORTED_LANGUAGES.map(lang => (
                                                                        <label key={lang} className={`px-3 py-1.5 rounded-lg border cursor-pointer text-xs uppercase ${q.codeSnippets[lang] !== undefined ? 'bg-green-600/30 border-green-500 text-green-300' : 'bg-gray-800/50 border-gray-600 text-gray-400'}`}>
                                                                            <input type="checkbox" className="sr-only" checked={q.codeSnippets[lang] !== undefined} onChange={() => toggleLanguage(qIndex, lang)} />
                                                                            {lang}
                                                                        </label>
                                                                    ))}
                                                                </div>
                                                            </div>

                                                            {/* Snippets */}
                                                            <div className="space-y-3">
                                                                {Object.keys(q.codeSnippets).map(lang => (
                                                                    <div key={lang}>
                                                                        <label className="block text-xs mb-1 text-green-400 uppercase">{lang} Code</label>
                                                                        <textarea
                                                                            value={q.codeSnippets[lang]}
                                                                            onChange={(e) => updateCodeSnippet(qIndex, lang, e.target.value)}
                                                                            className="w-full px-4 py-2 bg-[#1e1e1e] border border-green-500/30 rounded-lg text-green-300 font-mono text-sm min-h-[150px] focus:border-green-500"
                                                                            placeholder={`Enter boilerplate for ${lang}...`}
                                                                            required
                                                                        />
                                                                    </div>
                                                                ))}
                                                            </div>

                                                            <textarea
                                                                value={q.explanation}
                                                                onChange={(e) => updateQuestion(qIndex, 'explanation', e.target.value)}
                                                                className="w-full px-4 py-2 bg-black/40 border border-green-500/20 rounded-lg text-white text-sm focus:border-green-500"
                                                                placeholder="Explanation..."
                                                                required
                                                            />
                                                        </div>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    </div>

                                    <div className="flex gap-4 pt-4 border-t border-green-500/20">
                                        <button type="submit" disabled={actionLoading} className="flex-1 py-3 bg-green-600 hover:bg-green-500 text-white rounded-lg font-mono font-bold flex justify-center items-center gap-2">
                                            {actionLoading ? <Loader2 className="animate-spin" size={18} /> : (editingContestId ? 'UPDATE' : 'DEPLOY CONTEST')}
                                        </button>
                                    </div>
                                </form>
                            </motion.div>
                        </div>
                    )}
                </AnimatePresence>

                {/* Announcement Modal */}
                <AnimatePresence>
                    {showAnnouncementModal && (
                        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                            <motion.div initial={{ scale: 0.95, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.95, y: 20 }} className="bg-gray-900 border border-blue-500/30 rounded-2xl max-w-lg w-full p-6 shadow-2xl">
                                <div className="flex justify-between items-center mb-6">
                                    <h2 className="text-xl font-bold text-white flex items-center gap-2"><Megaphone className="text-blue-500" /> Post Announcement</h2>
                                    <button onClick={() => setShowAnnouncementModal(false)} className="text-gray-400 hover:text-white"><X size={20} /></button>
                                </div>
                                <form onSubmit={handleAnnouncementSubmit} className="space-y-4">
                                    <input
                                        type="text"
                                        value={announcementForm.title}
                                        onChange={(e) => setAnnouncementForm({ ...announcementForm, title: e.target.value })}
                                        className="w-full px-4 py-2 bg-black/40 border border-blue-500/20 rounded-lg text-white text-sm focus:border-blue-500"
                                        required placeholder="Announcement Title"
                                    />
                                    <textarea
                                        value={announcementForm.content}
                                        onChange={(e) => setAnnouncementForm({ ...announcementForm, content: e.target.value })}
                                        className="w-full px-4 py-2 bg-black/40 border border-blue-500/20 rounded-lg text-white text-sm min-h-[100px] focus:border-blue-500"
                                        required placeholder="Content details..."
                                    />
                                    <input
                                        type="text"
                                        value={announcementForm.attachmentUrl}
                                        onChange={(e) => setAnnouncementForm({ ...announcementForm, attachmentUrl: e.target.value })}
                                        className="w-full px-4 py-2 bg-black/40 border border-blue-500/20 rounded-lg text-white text-sm focus:border-blue-500"
                                        placeholder="Attachment Link (Optional URLs like Drive/Docs)"
                                    />
                                    <button type="submit" disabled={actionLoading} className="w-full py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg font-medium flex justify-center mt-4">
                                        {actionLoading ? <Loader2 className="animate-spin" size={18} /> : 'Post Announcement'}
                                    </button>
                                </form>
                            </motion.div>
                        </div>
                    )}
                </AnimatePresence>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import api from '@/lib/api';
import { useAuth } from '@/contexts/AuthContext';
import { BookOpen, Search, Check, X, ShieldAlert, FileText, Download, ExternalLink, Eye } from 'lucide-react';
import { toast } from 'react-hot-toast';

export default function ReviewPapers() {
    const { user } = useAuth();
    const [papers, setPapers] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState('pending');

    const [rejectingId, setRejectingId] = useState<string | null>(null);
    const [rejectionReason, setRejectionReason] = useState('');

    const fetchPapers = async () => {
        setLoading(true);
        try {
            const { data } = await api.get('/learn/papers', {
                params: { status: statusFilter, limit: 50 },
                withCredentials: true
            });
            setPapers(data.items);
        } catch (error) {
            toast.error('Failed to fetch papers');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchPapers();
    }, [statusFilter]);

    const handleAction = async (id: string, action: 'approved' | 'rejected') => {
        if (action === 'rejected' && !rejectionReason.trim()) {
            toast.error('Please provide a reason for rejection');
            return;
        }

        try {
            await api.put(`/learn/papers/${id}/review`, {
                status: action,
                rejectionReason: action === 'rejected' ? rejectionReason : undefined
            }, { withCredentials: true });

            toast.success(`Paper ${action} successfully`);
            setRejectingId(null);
            setRejectionReason('');
            fetchPapers(); // refresh
        } catch (error) {
            toast.error(`Failed to ${action} paper`);
        }
    };

    const downloadFile = async (paper: any) => {
        try {
            const res = await api.get(`/learn/papers/${paper._id}/download`, {
                responseType: 'blob',
                withCredentials: true
            });
            const url = window.URL.createObjectURL(new Blob([res.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', paper.fileName);
            document.body.appendChild(link);
            link.click();
            link.remove();
        } catch {
            toast.error('Failed to download file');
        }
    };

    const previewFile = async (paper: any) => {
        try {
            const res = await api.get(`/learn/papers/${paper._id}/download`, {
                responseType: 'blob',
                withCredentials: true
            });
            const file = new Blob([res.data], { type: 'application/pdf' });
            const url = window.URL.createObjectURL(file);
            window.open(url, '_blank');
        } catch {
            toast.error('Failed to preview file');
        }
    };

    if (!user?.roles?.some((r: string) => ['admin', 'learn_admin'].includes(r))) {
        return (
            <div className="flex flex-col items-center justify-center p-8 min-h-screen">
                <ShieldAlert className="w-16 h-16 text-red-500 mb-4" />
                <h1 className="text-2xl font-bold text-white mb-2">Access Denied</h1>
            </div>
        );
    }

    return (
        <div className="p-6 md:p-8 w-full max-w-7xl mx-auto min-h-screen">
            <header className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-white tracking-tight mb-2 flex items-center gap-3">
                        <BookOpen className="w-8 h-8 text-emerald-500" />
                        Paper Review Queue
                    </h1>
                    <p className="text-white/60">
                        Review uploaded notes, assignments, and past papers before they go live.
                    </p>
                </div>

                <div className="flex bg-[#111] p-1 rounded-xl border border-white/10">
                    {['pending', 'approved', 'rejected'].map(status => (
                        <button
                            key={status}
                            onClick={() => setStatusFilter(status)}
                            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors capitalize ${statusFilter === status
                                ? 'bg-white/10 text-white'
                                : 'text-white/40 hover:text-white/80 hover:bg-white/5'
                                }`}
                        >
                            {status}
                        </button>
                    ))}
                </div>
            </header>

            <div className="space-y-4">
                {loading ? (
                    <div className="flex justify-center p-12">
                        <div className="w-8 h-8 rounded-full border-2 border-emerald-500/20 border-t-emerald-500 animate-spin" />
                    </div>
                ) : papers.length === 0 ? (
                    <div className="text-center py-20 bg-[#111] border border-white/5 rounded-2xl">
                        <FileText className="w-12 h-12 text-white/20 mx-auto mb-4" />
                        <h3 className="text-lg font-medium text-white mb-1">Queue Empty</h3>
                        <p className="text-white/50">No {statusFilter} papers found.</p>
                    </div>
                ) : (
                    papers.map(paper => (
                        <div key={paper._id} className="bg-[#111] border border-white/5 rounded-2xl p-6 transition-all hover:border-white/10">
                            <div className="flex flex-col md:flex-row gap-6 items-start justify-between">
                                <div className="flex-1 space-y-4">
                                    <div>
                                        <div className="flex items-center gap-3 mb-2">
                                            <h3 className="text-lg font-bold text-white">{paper.title}</h3>
                                            <span className="px-2.5 py-1 rounded-full text-xs font-medium bg-white/5 text-white/70 capitalize border border-white/10">
                                                {paper.paperType}
                                            </span>
                                        </div>
                                        <p className="text-white/60 text-sm flex gap-3">
                                            <span><strong>Course:</strong> {paper.courseId?.code}</span>
                                            <span>•</span>
                                            <span><strong>Year:</strong> {paper.year}</span>
                                            <span>•</span>
                                            <span><strong>Uploader:</strong> {paper.uploadedBy?.name || 'Unknown'}</span>
                                        </p>
                                    </div>

                                    {paper.description && (
                                        <p className="text-white/70 text-sm bg-white/5 p-3 rounded-xl border border-white/5">
                                            {paper.description}
                                        </p>
                                    )}

                                    {paper.rejectionReason && statusFilter === 'rejected' && (
                                        <div className="bg-red-500/10 border border-red-500/20 px-4 py-3 rounded-xl">
                                            <p className="text-sm text-red-400"><strong>Rejection Reason:</strong> {paper.rejectionReason}</p>
                                        </div>
                                    )}

                                    <div className="flex flex-wrap gap-3 mt-2">
                                        <button
                                            onClick={() => previewFile(paper)}
                                            className="inline-flex items-center gap-2 text-sm text-blue-400 hover:text-blue-300 transition-colors bg-blue-500/10 hover:bg-blue-500/20 px-3 py-1.5 rounded-lg"
                                        >
                                            <Eye className="w-4 h-4" /> Preview
                                        </button>
                                        <button
                                            onClick={() => downloadFile(paper)}
                                            className="inline-flex items-center gap-2 text-sm text-emerald-400 hover:text-emerald-300 transition-colors bg-emerald-500/10 hover:bg-emerald-500/20 px-3 py-1.5 rounded-lg"
                                        >
                                            <Download className="w-4 h-4" /> Download File ({(Math.max(1, paper.fileSize / 1024)).toFixed(0)} KB)
                                        </button>
                                        <a
                                            href={`/learn/papers`}
                                            target="_blank"
                                            className="inline-flex items-center gap-2 text-sm text-white/50 hover:text-white transition-colors px-3 py-1.5 rounded-lg hover:bg-white/5"
                                        >
                                            <ExternalLink className="w-4 h-4" /> View in Learn
                                        </a>
                                    </div>
                                </div>

                                {statusFilter === 'pending' && (
                                    <div className="shrink-0 flex flex-col gap-2 min-w-[200px]">
                                        {rejectingId === paper._id ? (
                                            <div className="flex flex-col gap-2 animate-in fade-in zoom-in duration-200">
                                                <input
                                                    type="text"
                                                    placeholder="Reason for rejection..."
                                                    value={rejectionReason}
                                                    onChange={(e) => setRejectionReason(e.target.value)}
                                                    className="w-full bg-black/50 border border-red-500/30 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-red-500"
                                                    autoFocus
                                                />
                                                <div className="flex gap-2">
                                                    <button
                                                        onClick={() => setRejectingId(null)}
                                                        className="flex-1 py-2 bg-white/5 hover:bg-white/10 text-white/70 text-sm font-medium rounded-lg transition-colors border border-white/10"
                                                    >
                                                        Cancel
                                                    </button>
                                                    <button
                                                        onClick={() => handleAction(paper._id, 'rejected')}
                                                        className="flex-1 py-2 bg-red-500/20 hover:bg-red-500/30 text-red-500 text-sm font-medium rounded-lg transition-colors border border-red-500/30"
                                                    >
                                                        Confirm
                                                    </button>
                                                </div>
                                            </div>
                                        ) : (
                                            <>
                                                <button
                                                    onClick={() => handleAction(paper._id, 'approved')}
                                                    className="w-full flex items-center justify-center gap-2 py-2.5 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 text-sm font-medium rounded-xl transition-colors border border-emerald-500/20"
                                                >
                                                    <Check className="w-4 h-4" /> Approve Paper
                                                </button>
                                                <button
                                                    onClick={() => {
                                                        setRejectingId(paper._id);
                                                        setRejectionReason('');
                                                    }}
                                                    className="w-full flex items-center justify-center gap-2 py-2.5 bg-red-500/10 hover:bg-red-500/20 text-red-400 text-sm font-medium rounded-xl transition-colors border border-red-500/20"
                                                >
                                                    <X className="w-4 h-4" /> Reject Paper
                                                </button>
                                            </>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import api from '@/lib/api';
import {
    Users,
    BookOpen,
    Calendar,
    MessageSquare,
    TrendingUp,
    ShieldAlert
} from 'lucide-react';
import { motion } from 'framer-motion';

export default function AdminOverview() {
    const { user } = useAuth();
    const [stats, setStats] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchStats = async () => {
            try {
                const response = await api.get('/admin/stats');
                setStats(response.data);
            } catch (error) {
                console.error('Failed to fetch admin stats:', error);
            } finally {
                setLoading(false);
            }
        };

        if (user) {
            fetchStats();
        }
    }, [user]);

    if (loading) {
        return (
            <div className="flex-1 flex items-center justify-center p-8 min-h-screen">
                <div className="w-8 h-8 rounded-full border-2 border-indigo-500/20 border-t-indigo-500 animate-spin" />
            </div>
        );
    }

    const statCards = [
        {
            title: 'Total Users',
            value: stats?.users || 0,
            icon: Users,
            color: 'from-blue-500/20 to-indigo-500/5',
            textColor: 'text-indigo-400',
            borderColor: 'border-indigo-500/20',
        },
        {
            title: 'Pending Papers',
            value: stats?.pendingPapers || 0,
            icon: BookOpen,
            color: 'from-emerald-500/20 to-teal-500/5',
            textColor: 'text-emerald-400',
            borderColor: 'border-emerald-500/20',
        },
        {
            title: 'Pending Events',
            value: stats?.pendingEvents || 0,
            icon: Calendar,
            color: 'from-orange-500/20 to-amber-500/5',
            textColor: 'text-orange-400',
            borderColor: 'border-orange-500/20',
        },
        {
            title: 'Open Complaints',
            value: stats?.openComplaints || 0,
            icon: MessageSquare,
            color: 'from-red-500/20 to-rose-500/5',
            textColor: 'text-red-400',
            borderColor: 'border-red-500/20',
        },
        {
            title: 'In Progress Complaints',
            value: stats?.inProgressComplaints || 0,
            icon: ShieldAlert,
            color: 'from-purple-500/20 to-fuchsia-500/5',
            textColor: 'text-purple-400',
            borderColor: 'border-purple-500/20',
        }
    ];

    return (
        <div className="p-6 md:p-8 w-full max-w-7xl mx-auto min-h-screen">
            <header className="mb-8">
                <h1 className="text-3xl font-bold text-white tracking-tight mb-2">
                    Admin Overview
                </h1>
                <p className="text-white/60">
                    Welcome back, {user?.name}. Here's what's happening across NexusJKLU today.
                </p>
            </header>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {statCards.map((stat, i) => {
                    const Icon = stat.icon;
                    return (
                        <motion.div
                            key={stat.title}
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: i * 0.1 }}
                            className={`p-6 rounded-3xl border bg-gradient-to-br ${stat.color} ${stat.borderColor} relative overflow-hidden group`}
                        >
                            <div className="absolute inset-0 bg-white/5 opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

                            <div className="flex items-start justify-between relative z-10">
                                <div>
                                    <p className="text-sm font-medium text-white/50 mb-1">
                                        {stat.title}
                                    </p>
                                    <div className="flex items-baseline gap-2">
                                        <h3 className="text-4xl font-bold text-white tracking-tight">
                                            {stat.value}
                                        </h3>
                                        <TrendingUp className={`w-4 h-4 ${stat.textColor} opacity-80`} />
                                    </div>
                                </div>
                                <div className={`p-3 rounded-2xl bg-black/20 backdrop-blur-sm border border-white/5`}>
                                    <Icon className={`w-6 h-6 ${stat.textColor}`} />
                                </div>
                            </div>
                        </motion.div>
                    );
                })}
            </div>

            <div className="mt-12 bg-white/[0.02] border border-white/10 rounded-3xl p-8 text-center max-w-2xl mx-auto shadow-2xl">
                <ShieldAlert className="w-12 h-12 text-indigo-400 mx-auto mb-4 opacity-80" />
                <h3 className="text-xl font-semibold text-white mb-2">Need to manage something specific?</h3>
                <p className="text-white/60 mb-6">
                    Use the sidebar navigation to dive deeper into Users, Review Papers, Manage Events, or Handle Complaints. Your available actions depend on your assigned administrative roles.
                </p>
                <div className="inline-flex gap-2">
                    {user?.roles?.map((role: string) => (
                        <span key={role} className="px-3 py-1 rounded-full bg-white/10 border border-white/5 text-xs font-medium text-white/80 capitalize">
                            {role.replace('_', ' ')}
                        </span>
                    ))}
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import api from '@/lib/api';
import { useAuth } from '@/contexts/AuthContext';
import { Search, Edit2, ShieldAlert, Check, X, ShieldCheck, Users } from 'lucide-react';
import { toast } from 'react-hot-toast';

interface User {
    _id: string;
    email: string;
    name: string;
    roles: string[];
    createdAt: string;
    profile?: {
        studentId?: string;
        rollNo?: string;
    };
}

export default function UserManagement() {
    const { user: currentUser } = useAuth();
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);

    // Editing State
    const [editingUserId, setEditingUserId] = useState<string | null>(null);
    const [editedRoles, setEditedRoles] = useState<string[]>([]);

    const ALL_ROLES = ['student', 'admin', 'council_admin', 'voice_admin', 'learn_admin', 'coordinator', 'coding_ta'];

    const fetchUsers = async () => {
        setLoading(true);
        try {
            const { data } = await api.get('/admin/users', {
                params: { page, limit: 15, search: searchTerm }
            });
            setUsers(data.users);
            setTotalPages(data.totalPages);
        } catch (error) {
            toast.error('Failed to fetch users');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        const debounce = setTimeout(() => {
            fetchUsers();
        }, 300);
        return () => clearTimeout(debounce);
    }, [page, searchTerm]);

    const handleSaveRole = async (userId: string) => {
        try {
            await api.put(`/admin/users/${userId}/role`, { roles: editedRoles });
            toast.success('Roles updated successfully');
            setEditingUserId(null);
            fetchUsers();
        } catch (error: any) {
            toast.error(error.response?.data?.error || 'Failed to update roles');
        }
    };

    const toggleRole = (role: string) => {
        setEditedRoles(prev =>
            prev.includes(role)
                ? prev.filter(r => r !== role)
                : [...prev, role]
        );
    };

    if (!currentUser?.roles?.includes('admin')) {
        return (
            <div className="flex flex-col items-center justify-center p-8 min-h-screen text-center">
                <ShieldAlert className="w-16 h-16 text-red-500 mb-4" />
                <h1 className="text-2xl font-bold text-white mb-2">Access Denied</h1>
                <p className="text-white/60">Only Super Admins can manage users and assign roles.</p>
            </div>
        );
    }

    return (
        <div className="p-6 md:p-8 w-full max-w-7xl mx-auto min-h-screen">
            <header className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-white tracking-tight mb-2 flex items-center gap-3">
                        <Users className="w-8 h-8 text-indigo-500" />
                        User Management
                    </h1>
                    <p className="text-white/60">
                        View all registered users and assign administrative roles.
                    </p>
                </div>

                <div className="relative max-w-sm w-full">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-white/40" />
                    <input
                        type="text"
                        placeholder="Search users by name or email..."
                        value={searchTerm}
                        onChange={(e) => { setSearchTerm(e.target.value); setPage(1); }}
                        className="w-full bg-[#111] border border-white/10 rounded-xl py-3 pl-12 pr-4 text-white placeholder-white/40 focus:outline-none focus:border-indigo-500/50 focus:ring-1 focus:ring-indigo-500/50 transition-all"
                    />
                </div>
            </header>

            <div className="bg-[#111] border border-white/10 rounded-2xl overflow-hidden shadow-2xl">
                <div className="overflow-x-auto">
                    <table className="w-full text-left bg-[#111]">
                        <thead className="bg-[#151515] border-b border-white/10 text-white/50 text-xs uppercase tracking-wider">
                            <tr>
                                <th className="px-6 py-4 font-medium">User</th>
                                <th className="px-6 py-4 font-medium">Student ID</th>
                                <th className="px-6 py-4 font-medium">Assigned Roles</th>
                                <th className="px-6 py-4 font-medium">Joined</th>
                                <th className="px-6 py-4 font-medium text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            {users.map(user => {
                                const isEditing = editingUserId === user._id;

                                return (
                                    <tr key={user._id} className="hover:bg-white/[0.02] border-b border-white/5 last:border-0 transition-colors">
                                        <td className="px-6 py-4">
                                            <p className="font-semibold text-white/90">{user.name}</p>
                                            <p className="text-sm text-white/50">{user.email}</p>
                                        </td>
                                        <td className="px-6 py-4 text-white/70 text-sm">
                                            {user.profile?.studentId || user.profile?.rollNo || <span className="text-white/30 italic">Not provided</span>}
                                        </td>
                                        <td className="px-6 py-4 max-w-md">
                                            {isEditing ? (
                                                <div className="flex flex-wrap gap-2">
                                                    {ALL_ROLES.map(role => (
                                                        <button
                                                            key={role}
                                                            onClick={() => toggleRole(role)}
                                                            className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-colors ${editedRoles.includes(role)
                                                                ? 'bg-indigo-500/20 text-indigo-300 border-indigo-500/50'
                                                                : 'bg-black/20 text-white/40 border-white/10 hover:border-white/20'
                                                                }`}
                                                        >
                                                            {role.replace('_', ' ')}
                                                        </button>
                                                    ))}
                                                </div>
                                            ) : (
                                                <div className="flex flex-wrap gap-2">
                                                    {user.roles.map(role => (
                                                        <span key={role} className={`px-2 py-1 rounded-md text-xs font-medium border ${role === 'admin' ? 'bg-rose-500/10 text-rose-400 border-rose-500/20' :
                                                            role.includes('admin') ? 'bg-purple-500/10 text-purple-400 border-purple-500/20' :
                                                                'bg-white/5 text-white/70 border-white/10'
                                                            }`}>
                                                            {role.replace('_', ' ')}
                                                        </span>
                                                    ))}
                                                </div>
                                            )}
                                        </td>
                                        <td className="px-6 py-4 text-white/50 text-sm whitespace-nowrap">
                                            {new Date(user.createdAt).toLocaleDateString()}
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            {isEditing ? (
                                                <div className="flex justify-end gap-2">
                                                    <button
                                                        onClick={() => setEditingUserId(null)}
                                                        className="p-2 text-white/50 hover:bg-white/10 rounded-lg transition-colors"
                                                        title="Cancel"
                                                    >
                                                        <X className="w-5 h-5" />
                                                    </button>
                                                    <button
                                                        onClick={() => handleSaveRole(user._id)}
                                                        className="p-2 text-emerald-400 hover:bg-emerald-500/10 rounded-lg transition-colors"
                                                        title="Save Changes"
                                                    >
                                                        <Check className="w-5 h-5" />
                                                    </button>
                                                </div>
                                            ) : (
                                                <button
                                                    onClick={() => {
                                                        setEditingUserId(user._id);
                                                        setEditedRoles(user.roles);
                                                    }}
                                                    className="p-2 text-indigo-400 hover:bg-indigo-500/10 rounded-lg transition-colors"
                                                    disabled={currentUser.email === user.email} // prevent editing own roles here
                                                    title={currentUser.email === user.email ? "Cannot edit own roles here" : "Edit Roles"}
                                                >
                                                    <Edit2 className="w-5 h-5" />
                                                </button>
                                            )}
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>

                    {!loading && users.length === 0 && (
                        <div className="text-center py-12 text-white/50">
                            No users found matching "{searchTerm}"
                        </div>
                    )}

                    {loading && (
                        <div className="flex justify-center p-8">
                            <div className="w-6 h-6 rounded-full border-2 border-indigo-500/20 border-t-indigo-500 animate-spin" />
                        </div>
                    )}
                </div>

                {/* Pagination */}
                {totalPages > 1 && (
                    <div className="bg-[#151515] border-t border-white/10 p-4 flex justify-between items-center text-sm text-white/60">
                        <button
                            disabled={page === 1}
                            onClick={() => setPage(p => p - 1)}
                            className="px-4 py-2 bg-[#222] hover:bg-[#333] disabled:opacity-50 rounded-lg transition-colors"
                        >
                            Previous
                        </button>
                        <span>Page {page} of {totalPages}</span>
                        <button
                            disabled={page === totalPages}
                            onClick={() => setPage(p => p + 1)}
                            className="px-4 py-2 bg-[#222] hover:bg-[#333] disabled:opacity-50 rounded-lg transition-colors"
                        >
                            Next
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import api from '@/lib/api';
import { useAuth } from '@/contexts/AuthContext';
import { MessageSquare, ShieldAlert, FileText, Check, Clock, ShieldCheck } from 'lucide-react';
import { toast } from 'react-hot-toast';

export default function ReviewComplaints() {
    const { user } = useAuth();
    const [complaints, setComplaints] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState('all');

    const [respondingId, setRespondingId] = useState<string | null>(null);
    const [responseText, setResponseText] = useState('');
    const [responseStatus, setResponseStatus] = useState('in_progress');

    const fetchComplaints = async () => {
        setLoading(true);
        try {
            const params: any = { limit: 50 };
            if (statusFilter !== 'all') params.status = statusFilter;

            const { data } = await api.get('/voice/admin/complaints', {
                params,
                withCredentials: true
            });
            setComplaints(data.items);
        } catch (error) {
            toast.error('Failed to fetch complaints');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchComplaints();
    }, [statusFilter]);

    const handleUpdate = async (id: string, newStatus?: string) => {
        if (respondingId === id && !responseText.trim() && !newStatus) {
            toast.error('Response text cannot be empty');
            return;
        }

        try {
            const payload: any = {};
            if (newStatus) payload.status = newStatus;

            if (respondingId === id) {
                payload.response = responseText;
                payload.status = responseStatus;
            }

            await api.put(`/voice/admin/complaints/${id}`, payload, { withCredentials: true });

            toast.success(`Complaint updated`);
            setRespondingId(null);
            setResponseText('');
            fetchComplaints();
        } catch (error) {
            toast.error(`Failed to update complaint`);
        }
    };

    if (!user?.roles?.some((r: string) => ['admin', 'voice_admin'].includes(r))) {
        return (
            <div className="flex flex-col items-center justify-center p-8 min-h-screen">
                <ShieldAlert className="w-16 h-16 text-red-500 mb-4" />
                <h1 className="text-2xl font-bold text-white mb-2">Access Denied</h1>
            </div>
        );
    }

    return (
        <div className="p-6 md:p-8 w-full max-w-7xl mx-auto min-h-screen">
            <header className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-white tracking-tight mb-2 flex items-center gap-3">
                        <MessageSquare className="w-8 h-8 text-rose-500" />
                        Complaints Inbox
                    </h1>
                    <p className="text-white/60">
                        Review, investigate, and respond to student complaints and issues.
                    </p>
                </div>

                <div className="flex bg-[#111] p-1 rounded-xl border border-white/10 overflow-x-auto">
                    {['all', 'open', 'in_progress', 'resolved', 'closed'].map(status => (
                        <button
                            key={status}
                            onClick={() => setStatusFilter(status)}
                            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors capitalize whitespace-nowrap ${statusFilter === status
                                    ? 'bg-white/10 text-white'
                                    : 'text-white/40 hover:text-white/80 hover:bg-white/5'
                                }`}
                        >
                            {status.replace('_', ' ')}
                        </button>
                    ))}
                </div>
            </header>

            <div className="space-y-4">
                {loading ? (
                    <div className="flex justify-center p-12">
                        <div className="w-8 h-8 rounded-full border-2 border-rose-500/20 border-t-rose-500 animate-spin" />
                    </div>
                ) : complaints.length === 0 ? (
                    <div className="text-center py-20 bg-[#111] border border-white/5 rounded-2xl">
                        <ShieldCheck className="w-12 h-12 text-white/20 mx-auto mb-4" />
                        <h3 className="text-lg font-medium text-white mb-1">Inbox Clear</h3>
                        <p className="text-white/50">No {statusFilter.replace('_', ' ')} complaints found.</p>
                    </div>
                ) : (
                    complaints.map(complaint => (
                        <div key={complaint._id} className="bg-[#111] border border-white/5 rounded-2xl p-6 transition-all hover:border-white/10">
                            <div className="flex flex-col md:flex-row gap-6 items-start justify-between">
                                <div className="flex-1 space-y-4 w-full">
                                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                                        <div>
                                            <div className="flex items-center gap-3 mb-2">
                                                <h3 className="text-lg font-bold text-white">{complaint.title}</h3>
                                                <span className={`px-2.5 py-1 rounded-full text-xs font-medium capitalize border ${complaint.priority === 'high' ? 'bg-red-500/10 text-red-400 border-red-500/20' :
                                                        complaint.priority === 'medium' ? 'bg-orange-500/10 text-orange-400 border-orange-500/20' :
                                                            'bg-blue-500/10 text-blue-400 border-blue-500/20'
                                                    }`}>
                                                    {complaint.priority} Priority
                                                </span>
                                                <span className={`px-2.5 py-1 rounded-full text-xs font-medium capitalize border ${complaint.status === 'open' ? 'bg-rose-500/10 text-rose-400 border-rose-500/20' :
                                                        complaint.status === 'in_progress' ? 'bg-amber-500/10 text-amber-400 border-amber-500/20' :
                                                            'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'
                                                    }`}>
                                                    {complaint.status.replace('_', ' ')}
                                                </span>
                                            </div>
                                            <p className="text-white/60 text-sm flex gap-3 flex-wrap">
                                                <span><strong>ID:</strong> {complaint.ticketId}</span>
                                                <span>• <strong>Cat:</strong> {complaint.category}</span>
                                                <span>• <strong>By:</strong> {complaint.isAnonymous ? 'Anonymous' : complaint.userId?.name || 'Unknown'}</span>
                                                <span>• {new Date(complaint.createdAt).toLocaleDateString()}</span>
                                            </p>
                                        </div>
                                    </div>

                                    <div className="bg-white/[0.03] p-4 rounded-xl border border-white/5 font-mono text-sm text-white/80">
                                        {complaint.description}
                                    </div>

                                    {complaint.response && (
                                        <div className="bg-indigo-500/5 p-4 rounded-xl border border-indigo-500/10 mt-4">
                                            <p className="text-xs text-indigo-400/80 uppercase font-bold tracking-wider mb-2">
                                                Admin Response (from {complaint.respondedBy?.name || 'Admin'})
                                            </p>
                                            <p className="text-sm text-indigo-100/90">{complaint.response}</p>
                                        </div>
                                    )}

                                    {respondingId === complaint._id && (
                                        <div className="flex flex-col gap-3 mt-4 p-4 border border-rose-500/20 bg-rose-500/5 rounded-xl animate-in fade-in zoom-in duration-200">
                                            <p className="text-sm font-medium text-rose-300">New Response</p>
                                            <textarea
                                                placeholder="Write an official response to the student..."
                                                value={responseText}
                                                onChange={(e) => setResponseText(e.target.value)}
                                                rows={3}
                                                className="w-full bg-black/50 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-rose-500/50 resize-y"
                                                autoFocus
                                            />
                                            <div className="flex flex-col sm:flex-row gap-3 items-center justify-between">
                                                <div className="flex items-center gap-2 w-full sm:w-auto">
                                                    <span className="text-sm text-white/50">Set Status:</span>
                                                    <select
                                                        value={responseStatus}
                                                        onChange={(e) => setResponseStatus(e.target.value)}
                                                        className="bg-[#111] border border-white/10 rounded-lg px-3 py-1.5 text-sm text-white focus:outline-none"
                                                    >
                                                        <option value="in_progress">In Progress</option>
                                                        <option value="resolved">Resolved</option>
                                                        <option value="closed">Closed</option>
                                                    </select>
                                                </div>
                                                <div className="flex gap-2 w-full sm:w-auto">
                                                    <button
                                                        onClick={() => setRespondingId(null)}
                                                        className="flex-1 sm:flex-none px-4 py-2 bg-white/5 hover:bg-white/10 text-white/70 text-sm font-medium rounded-lg transition-colors border border-white/10"
                                                    >
                                                        Cancel
                                                    </button>
                                                    <button
                                                        onClick={() => handleUpdate(complaint._id)}
                                                        className="flex-1 sm:flex-none px-4 py-2 bg-rose-500/20 hover:bg-rose-500/30 text-rose-400 text-sm font-medium rounded-lg transition-colors border border-rose-500/30"
                                                    >
                                                        Submit Response
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </div>

                                <div className="shrink-0 flex flex-col gap-2 w-full md:w-auto md:min-w-[160px]">
                                    {['open', 'in_progress'].includes(complaint.status) && respondingId !== complaint._id && (
                                        <button
                                            onClick={() => {
                                                setRespondingId(complaint._id);
                                                setResponseText(complaint.response || '');
                                                setResponseStatus(complaint.status === 'open' ? 'in_progress' : complaint.status);
                                            }}
                                            className="w-full flex items-center justify-center gap-2 py-2.5 bg-rose-500/10 hover:bg-rose-500/20 text-rose-400 text-sm font-medium rounded-xl transition-colors border border-rose-500/20"
                                        >
                                            <MessageSquare className="w-4 h-4" /> Add Response
                                        </button>
                                    )}

                                    {complaint.status === 'open' && respondingId !== complaint._id && (
                                        <button
                                            onClick={() => handleUpdate(complaint._id, 'in_progress')}
                                            className="w-full flex items-center justify-center gap-2 py-2.5 bg-amber-500/10 hover:bg-amber-500/20 text-amber-400 text-sm font-medium rounded-xl transition-colors border border-amber-500/20"
                                        >
                                            <Clock className="w-4 h-4" /> Move to Progress
                                        </button>
                                    )}

                                    {['open', 'in_progress'].includes(complaint.status) && respondingId !== complaint._id && (
                                        <button
                                            onClick={() => handleUpdate(complaint._id, 'resolved')}
                                            className="w-full flex items-center justify-center gap-2 py-2.5 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 text-sm font-medium rounded-xl transition-colors border border-emerald-500/20"
                                        >
                                            <Check className="w-4 h-4" /> Mark Resolved
                                        </button>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { Mail, Shield, Lock, ArrowLeft, Loader2, CheckCircle2 } from 'lucide-react';
import Image from 'next/image';
import axios from 'axios';
import { useAuth } from '@/contexts/AuthContext';

const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';

export default function ForgotPassword() {
    const [email, setEmail] = useState('');
    const [otp, setOtp] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [step, setStep] = useState<'email' | 'otp' | 'reset'>('email');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);

    const router = useRouter();
    const { login } = useAuth(); // If we want to auto-login after reset

    const handleSendOTP = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            await axios.post(`${API_BASE_URL}/auth/send-otp`, { email });
            setStep('otp');
        } catch (err: any) {
            setError(err.response?.data?.error || err.response?.data?.message || 'Failed to send OTP. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const handleVerifyOTP = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        if (otp.length !== 6) {
            setError('Please enter a valid 6-digit OTP');
            return;
        }

        setLoading(true);
        try {
            // Optional: You can either verify OTP here to auto-login the user, or just move to the reset step
            // Our backend supports immediate verify which returns a token, but let's just proceed to Reset Password
            const response = await axios.post(`${API_BASE_URL}/auth/verify-otp`, { email, otp });
            // If valid, backend returns token (legacy behavior). We will proceed to reset step.
            setStep('reset');
        } catch (err: any) {
            setError(err.response?.data?.error || 'Invalid or expired OTP');
        } finally {
            setLoading(false);
        }
    };

    const handleResetPassword = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        if (newPassword !== confirmPassword) {
            setError('Passwords do not match');
            return;
        }

        if (newPassword.length < 6) {
            setError('Password must be at least 6 characters');
            return;
        }

        setLoading(true);

        try {
            await axios.post(`${API_BASE_URL}/auth/reset-password`, {
                email,
                otp,
                newPassword
            });

            setSuccess(true);
            setTimeout(() => {
                router.push('/auth/login');
            }, 2000);
        } catch (err: any) {
            setError(err.response?.data?.error || 'Failed to reset password. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const handleBack = () => {
        if (step === 'otp') {
            setStep('email');
            setOtp('');
        } else if (step === 'reset') {
            setStep('otp');
            setNewPassword('');
            setConfirmPassword('');
        }
        setError('');
    };

    return (
        <div className="min-h-screen bg-[#050505] flex flex-col justify-center py-12 px-4 sm:px-6 lg:px-8 relative overflow-hidden">
            {/* Background elements (matching login) */}
            <div className="absolute inset-0 z-0">
                <div className="absolute inset-0 bg-transparent" />
                <div className="absolute top-0 right-0 -mr-40 w-96 h-96 rounded-full bg-emerald-500/10 blur-[120px]" />
                <div className="absolute bottom-0 left-0 -ml-40 w-96 h-96 rounded-full bg-indigo-500/10 blur-[120px]" />
            </div>

            <div className="relative z-10 sm:mx-auto sm:w-full sm:max-w-md">
                <motion.div
                    initial={{ opacity: 0, y: -20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="flex justify-center"
                >
                    <Link href="/">
                        <div className="relative w-16 h-16 flex items-center justify-center transition-transform hover:scale-105">
                            <Image
                                src="/white_jklu_logo.png"
                                alt="JKLU Logo"
                                fill
                                className="object-contain drop-shadow-2xl"
                            />
                        </div>
                    </Link>
                </motion.div>

                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    transition={{ delay: 0.1 }}
                    className="mt-6 text-center"
                >
                    <h2 className="text-3xl font-extrabold text-white tracking-tight">
                        {step === 'email' && 'Forgot Password'}
                        {step === 'otp' && 'Verify OTP'}
                        {step === 'reset' && 'Reset Password'}
                    </h2>
                    <p className="mt-2 text-sm text-gray-400">
                        {step === 'email' && 'Enter your email to receive a password reset code'}
                        {step === 'otp' && 'Enter the 6-digit code sent to your email'}
                        {step === 'reset' && 'Create your new password'}
                    </p>
                </motion.div>
            </div>

            <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md relative z-10">
                <motion.div
                    initial={{ opacity: 0, scale: 0.98 }}
                    animate={{ opacity: 1, scale: 1 }}
                    transition={{ delay: 0.2 }}
                    className="bg-zinc-900/50 backdrop-blur-xl py-8 px-4 border border-zinc-800 rounded-2xl shadow-2xl sm:px-10"
                >
                    <AnimatePresence mode="wait">
                        {success ? (
                            <motion.div
                                key="success"
                                initial={{ opacity: 0, scale: 0.95 }}
                                animate={{ opacity: 1, scale: 1 }}
                                className="bg-emerald-500/10 border border-emerald-500/20 rounded-xl p-6 text-center"
                            >
                                <CheckCircle2 className="mx-auto h-12 w-12 text-emerald-500 mb-4" />
                                <h3 className="text-emerald-400 font-semibold mb-2 text-lg">
                                    Password Reset Successful!
                                </h3>
                                <p className="text-emerald-500/80 text-sm">
                                    Redirecting to login page...
                                </p>
                            </motion.div>
                        ) : (
                            <motion.div
                                key={step}
                                initial={{ opacity: 0, x: 20 }}
                                animate={{ opacity: 1, x: 0 }}
                                exit={{ opacity: 0, x: -20 }}
                                transition={{ duration: 0.2 }}
                            >
                                {step === 'email' && (
                                    <form onSubmit={handleSendOTP} className="space-y-6">
                                        <div>
                                            <label htmlFor="email" className="block text-sm font-medium text-gray-300">
                                                Email Address
                                            </label>
                                            <div className="mt-2 relative">
                                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                                    <Mail className="h-5 w-5 text-gray-500" />
                                                </div>
                                                <input
                                                    id="email"
                                                    name="email"
                                                    type="email"
                                                    autoComplete="email"
                                                    required
                                                    value={email}
                                                    onChange={(e) => setEmail(e.target.value)}
                                                    className="appearance-none block w-full pl-10 pr-3 py-2.5 border border-zinc-700 bg-zinc-800/50 rounded-xl text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all sm:text-sm"
                                                    placeholder="student@jklu.edu.in"
                                                />
                                            </div>
                                        </div>

                                        {error && (
                                            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg">
                                                <p className="text-sm text-red-500 text-center">{error}</p>
                                            </motion.div>
                                        )}

                                        <button
                                            type="submit"
                                            disabled={loading}
                                            className="w-full flex justify-center py-2.5 px-4 border border-transparent rounded-xl shadow-sm text-sm font-medium text-black bg-emerald-500 hover:bg-emerald-400 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                        >
                                            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Send Reset Code'}
                                        </button>
                                    </form>
                                )}

                                {step === 'otp' && (
                                    <form onSubmit={handleVerifyOTP} className="space-y-6">
                                        <div>
                                            <div className="flex justify-between items-center mb-2">
                                                <label htmlFor="otp" className="block text-sm font-medium text-gray-300">
                                                    Enter OTP
                                                </label>
                                                <span className="text-xs text-gray-500">Sent to {email}</span>
                                            </div>
                                            <div className="mt-2 relative">
                                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                                    <Shield className="h-5 w-5 text-gray-500" />
                                                </div>
                                                <input
                                                    id="otp"
                                                    name="otp"
                                                    type="text"
                                                    required
                                                    value={otp}
                                                    onChange={(e) => setOtp(e.target.value.replace(/\D/g, '').slice(0, 6))}
                                                    className="appearance-none block w-full pl-10 pr-3 py-3 border border-zinc-700 bg-zinc-800/50 rounded-xl text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all text-center text-2xl tracking-[0.2em] font-mono sm:text-sm"
                                                    placeholder="000000"
                                                />
                                            </div>
                                        </div>

                                        {error && (
                                            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg">
                                                <p className="text-sm text-red-500 text-center">{error}</p>
                                            </motion.div>
                                        )}

                                        <div className="flex gap-3">
                                            <button
                                                type="button"
                                                onClick={handleBack}
                                                className="flex-1 py-2.5 px-4 border border-zinc-700 rounded-xl text-sm font-medium text-gray-300 hover:bg-zinc-800 transition-colors"
                                            >
                                                Back
                                            </button>
                                            <button
                                                type="submit"
                                                disabled={otp.length !== 6 || loading}
                                                className="flex-1 flex justify-center py-2.5 px-4 border border-transparent rounded-xl shadow-sm text-sm font-medium text-black bg-emerald-500 hover:bg-emerald-400 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                            >
                                                {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Verify OTP'}
                                            </button>
                                        </div>
                                    </form>
                                )}

                                {step === 'reset' && (
                                    <form onSubmit={handleResetPassword} className="space-y-6">
                                        <div>
                                            <label className="block text-sm font-medium text-gray-300">
                                                New Password
                                            </label>
                                            <div className="mt-2 relative">
                                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                                    <Lock className="h-5 w-5 text-gray-500" />
                                                </div>
                                                <input
                                                    type="password"
                                                    required
                                                    value={newPassword}
                                                    onChange={(e) => setNewPassword(e.target.value)}
                                                    className="appearance-none block w-full pl-10 pr-3 py-2.5 border border-zinc-700 bg-zinc-800/50 rounded-xl text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all sm:text-sm"
                                                    placeholder="Must be at least 6 characters"
                                                    minLength={6}
                                                />
                                            </div>
                                        </div>

                                        <div>
                                            <label className="block text-sm font-medium text-gray-300">
                                                Confirm New Password
                                            </label>
                                            <div className="mt-2 relative">
                                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                                    <Lock className="h-5 w-5 text-gray-500" />
                                                </div>
                                                <input
                                                    type="password"
                                                    required
                                                    value={confirmPassword}
                                                    onChange={(e) => setConfirmPassword(e.target.value)}
                                                    className="appearance-none block w-full pl-10 pr-3 py-2.5 border border-zinc-700 bg-zinc-800/50 rounded-xl text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all sm:text-sm"
                                                    placeholder="Confirm your password"
                                                    minLength={6}
                                                />
                                            </div>
                                        </div>

                                        {error && (
                                            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg">
                                                <p className="text-sm text-red-500 text-center">{error}</p>
                                            </motion.div>
                                        )}

                                        <div className="flex gap-3">
                                            <button
                                                type="button"
                                                onClick={handleBack}
                                                className="flex-1 py-2.5 px-4 border border-zinc-700 rounded-xl text-sm font-medium text-gray-300 hover:bg-zinc-800 transition-colors"
                                            >
                                                Back
                                            </button>
                                            <button
                                                type="submit"
                                                disabled={loading || newPassword.length < 6 || newPassword !== confirmPassword}
                                                className="flex-1 flex justify-center py-2.5 px-4 border border-transparent rounded-xl shadow-sm text-sm font-medium text-black bg-emerald-500 hover:bg-emerald-400 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                            >
                                                {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Reset Password'}
                                            </button>
                                        </div>
                                    </form>
                                )}
                            </motion.div>
                        )}
                    </AnimatePresence>

                    {!success && (
                        <div className="mt-6 text-center">
                            <Link
                                href="/auth/login"
                                className="inline-flex items-center text-sm font-medium text-emerald-500 hover:text-emerald-400 transition-colors"
                            >
                                <ArrowLeft className="w-4 h-4 mr-2" />
                                Back to login
                            </Link>
                        </div>
                    )}
                </motion.div>
            </div>
        </div>
    );
}

'use client';

import { useState } from 'react';
import { motion } from 'framer-motion';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { LogIn, Eye, EyeOff, AlertCircle } from 'lucide-react';

export default function LoginPage() {
    const { login } = useAuth();
    const router = useRouter();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            await login(email, password);
            router.push('/');
        } catch (err: any) {
            setError(err.response?.data?.error || 'Login failed. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center px-4 relative">
            <div className="glow-orb w-[400px] h-[400px] -top-32 -right-32 bg-[var(--primary)]" style={{ opacity: 0.08 }} />

            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                className="w-full max-w-md"
            >
                <div className="glass-card p-8">
                    <div className="text-center mb-8">
                        <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-[var(--primary)] to-[var(--primary-dark)] flex items-center justify-center mx-auto mb-4 shadow-lg shadow-[var(--primary)]/20">
                            <LogIn className="w-7 h-7 text-white" />
                        </div>
                        <h1 className="text-2xl font-bold text-white">Welcome Back</h1>
                        <p className="text-white/40 text-sm mt-1">Sign in to NexusJKLU</p>
                    </div>

                    {error && (
                        <div className="flex items-center gap-2 p-3 mb-6 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-sm">
                            <AlertCircle className="w-4 h-4 flex-shrink-0" />
                            {error}
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div>
                            <label className="text-sm text-white/50 mb-1.5 block">Email</label>
                            <input
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                className="input-field"
                                placeholder="your@jklu.edu.in"
                                required
                            />
                        </div>

                        <div>
                            <div className="flex justify-between items-center mb-1.5">
                                <label className="text-sm text-white/50 block">Password</label>
                                <Link href="/auth/forgot-password" className="text-sm text-[var(--primary)] hover:text-[var(--primary-light)] font-medium transition-colors">
                                    Forgot password?
                                </Link>
                            </div>
                            <div className="relative">
                                <input
                                    type={showPassword ? 'text' : 'password'}
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="input-field pr-10"
                                    placeholder="••••••••"
                                    required
                                />
                                <button
                                    type="button"
                                    onClick={() => setShowPassword(!showPassword)}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 text-white/30 hover:text-white/60"
                                >
                                    {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                </button>
                            </div>
                        </div>

                        <button
                            type="submit"
                            disabled={loading}
                            className="btn-primary w-full flex items-center justify-center gap-2 disabled:opacity-50"
                        >
                            {loading ? (
                                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                            ) : (
                                <>
                                    <LogIn className="w-4 h-4" />
                                    Sign In
                                </>
                            )}
                        </button>
                    </form>

                    <p className="text-center text-sm text-white/30 mt-6">
                        Don&apos;t have an account?{' '}
                        <Link href="/auth/register" className="text-[var(--primary)] hover:text-[var(--primary-light)] font-medium">
                            Sign Up
                        </Link>
                    </p>
                </div>
            </motion.div>
        </div>
    );
}

'use client';

import { useState } from 'react';
import { motion } from 'framer-motion';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { UserPlus, Eye, EyeOff, AlertCircle } from 'lucide-react';

export default function RegisterPage() {
    const { register } = useAuth();
    const router = useRouter();
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        if (password !== confirmPassword) {
            setError('Passwords do not match');
            return;
        }
        if (password.length < 6) {
            setError('Password must be at least 6 characters');
            return;
        }

        setLoading(true);
        try {
            await register(email, name, password);
            router.push('/');
        } catch (err: any) {
            setError(err.response?.data?.error || err.response?.data?.errors?.[0]?.msg || 'Registration failed');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center px-4 relative">
            <div className="glow-orb w-[400px] h-[400px] -bottom-32 -left-32 bg-[var(--secondary)]" style={{ opacity: 0.08 }} />

            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                className="w-full max-w-md"
            >
                <div className="glass-card p-8">
                    <div className="text-center mb-8">
                        <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-[var(--secondary)] to-[var(--secondary-dark)] flex items-center justify-center mx-auto mb-4 shadow-lg shadow-[var(--secondary)]/20">
                            <UserPlus className="w-7 h-7 text-white" />
                        </div>
                        <h1 className="text-2xl font-bold text-white">Create Account</h1>
                        <p className="text-white/40 text-sm mt-1">Join NexusJKLU community</p>
                    </div>

                    {error && (
                        <div className="flex items-center gap-2 p-3 mb-6 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-sm">
                            <AlertCircle className="w-4 h-4 flex-shrink-0" />
                            {error}
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div>
                            <label className="text-sm text-white/50 mb-1.5 block">Full Name</label>
                            <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="input-field" placeholder="Your Name" required />
                        </div>
                        <div>
                            <label className="text-sm text-white/50 mb-1.5 block">Email</label>
                            <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="input-field" placeholder="your@jklu.edu.in" required />
                        </div>
                        <div>
                            <label className="text-sm text-white/50 mb-1.5 block">Password</label>
                            <div className="relative">
                                <input type={showPassword ? 'text' : 'password'} value={password} onChange={(e) => setPassword(e.target.value)} className="input-field pr-10" placeholder="••••••••" required />
                                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-white/30 hover:text-white/60">
                                    {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                </button>
                            </div>
                        </div>
                        <div>
                            <label className="text-sm text-white/50 mb-1.5 block">Confirm Password</label>
                            <input type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} className="input-field" placeholder="••••••••" required />
                        </div>

                        <button type="submit" disabled={loading} className="btn-primary w-full flex items-center justify-center gap-2 disabled:opacity-50"
                            style={{ background: 'linear-gradient(135deg, var(--secondary), var(--secondary-dark))' }}>
                            {loading ? <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <><UserPlus className="w-4 h-4" />Sign Up</>}
                        </button>
                    </form>

                    <p className="text-center text-sm text-white/30 mt-6">
                        Already have an account?{' '}
                        <Link href="/auth/login" className="text-[var(--secondary)] hover:text-[var(--secondary-light)] font-medium">Sign In</Link>
                    </p>
                </div>
            </motion.div>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { useParams } from 'next/navigation';
import api from '@/lib/api';
import { format } from 'date-fns';
import Image from 'next/image';
import { Calendar, MapPin, Users, Mail, User, Info, ChevronLeft } from 'lucide-react';
import { getClubLogo } from '@/lib/club-assets';
import Link from 'next/link';
import ClubEventCard from '@/components/ClubEventCard';

const getThemeColor = (str: string) => {
    const n = str.toLowerCase();
    if (n.includes('tech') || n.includes('code')) return { primary: '#3B82F6', gradient: 'from-blue-600 to-indigo-600' };
    if (n.includes('art') || n.includes('design') || n.includes('drama')) return { primary: '#F97316', gradient: 'from-orange-500 to-red-600' };
    if (n.includes('music') || n.includes('dance')) return { primary: '#F59E0B', gradient: 'from-amber-500 to-orange-600' };
    if (n.includes('sport')) return { primary: '#EF4444', gradient: 'from-red-600 to-orange-700' };
    return { primary: '#3B82F6', gradient: 'from-blue-500 to-cyan-500' };
};

export default function ClubDetailPage() {
    const params = useParams();
    const [club, setClub] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [theme, setTheme] = useState<any>({ primary: '#3B82F6', gradient: 'from-blue-600 to-indigo-600' });

    useEffect(() => {
        api.get(`/api/council/clubs/${params.slug}`)
            .then(res => {
                const c = res.data.club || res.data;
                setClub(c);
                if (c) setTheme(getThemeColor(c.name));
            })
            .catch(console.error)
            .finally(() => setLoading(false));
    }, [params.slug]);

    if (loading) return (
        <div className="min-h-screen flex items-center justify-center">
            <div className="w-12 h-12 border-4 border-white/10 border-t-blue-500 rounded-full animate-spin" />
        </div>
    );

    if (!club) return (
        <div className="min-h-screen flex flex-col items-center justify-center">
            <h2 className="text-2xl font-bold text-white mb-4">Club not found</h2>
            <Link href="/council/clubs" className="text-[var(--primary)] hover:underline">Back to Clubs</Link>
        </div>
    );

    return (
        <div className="min-h-screen relative pb-20">
            <div className="glow-orb w-[600px] h-[600px] -top-48 -right-48 bg-blue-500" style={{ opacity: 0.06 }} />
            <div className="glow-orb w-[600px] h-[600px] -bottom-48 -left-48 bg-orange-500" style={{ opacity: 0.06 }} />

            {/* Dynamic Header */}
            <div className="relative pt-24 pb-20 px-4 overflow-hidden">
                <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient} opacity-10`} />
                <div className="absolute inset-0 bg-gradient-to-b from-transparent to-[var(--background)]" />

                <div className="max-w-7xl mx-auto relative z-10 flex flex-col md:flex-row items-center gap-8">
                    <Link href="/council/clubs" className="absolute top-[-40px] left-0 text-white/40 hover:text-white flex items-center transition-colors text-sm">
                        <ChevronLeft className="w-4 h-4 mr-1" /> Back to Clubs
                    </Link>

                    <div className="w-32 h-32 md:w-40 md:h-40 bg-white/5 backdrop-blur-xl rounded-2xl flex items-center justify-center border border-white/10 shadow-2xl relative overflow-hidden group">
                        {getClubLogo(club.slug) ? (
                            <div className="relative w-full h-full p-4 group-hover:scale-110 transition-transform duration-500">
                                <Image src={getClubLogo(club.slug)!} alt={`${club.name} logo`} fill className="object-contain drop-shadow-lg" />
                            </div>
                        ) : (
                            <Users className="w-16 h-16 text-white/50" />
                        )}
                    </div>

                    <div className="text-center md:text-left">
                        <h1 className="text-4xl md:text-6xl font-black mb-4 tracking-tight text-white">{club.name}</h1>
                        {club.council_name && (
                            <div className="inline-flex items-center px-4 py-1.5 rounded-full bg-white/5 border border-white/10 backdrop-blur-md">
                                <span className="text-sm font-medium text-white/50">Part of <span className="text-white font-bold">{club.council_name}</span></span>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-20">
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    {/* Main */}
                    <div className="lg:col-span-2 space-y-8">
                        <div className="glass-card p-8">
                            <h2 className="text-2xl font-bold text-white mb-6 flex items-center">
                                <Info className="w-6 h-6 mr-3" style={{ color: theme.primary }} /> About Us
                            </h2>
                            <p className="text-white/40 text-lg leading-relaxed whitespace-pre-wrap">
                                {club.description || "No description provided yet."}
                            </p>
                        </div>

                        <div className="glass-card p-8">
                            <h2 className="text-2xl font-bold text-white mb-6 flex items-center">
                                <Calendar className="w-6 h-6 mr-3" style={{ color: theme.primary }} /> Upcoming Events
                            </h2>
                            {club.events && club.events.length > 0 ? (
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    {club.events.map((event: any) => (
                                        <ClubEventCard key={event.id || event._id} id={event.id || event._id} title={event.title} date={event.start_date || event.date} venue={event.venue} imageUrl={event.image_url} status={event.status} desc={event.description} is_enrolled={event.is_enrolled} />
                                    ))}
                                </div>
                            ) : (
                                <div className="text-center py-12 bg-white/[0.02] rounded-2xl border border-white/5">
                                    <Calendar className="w-12 h-12 text-white/10 mx-auto mb-4" />
                                    <p className="text-white/30 font-medium">No upcoming events scheduled</p>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Sidebar - Leadership */}
                    <div className="lg:col-span-1">
                        <div className="glass-card p-8 sticky top-24">
                            <h2 className="text-xl font-bold text-white mb-6 border-b border-white/10 pb-4">Leadership Team</h2>
                            <div className="space-y-6">
                                {[
                                    { title: 'Chairperson', person: club.chair_name, email: club.chair_email },
                                    { title: 'Co-Chairperson', person: club.co_chair_name, email: club.co_chair_email },
                                    { title: 'Secretary', person: club.secretary_name, email: club.secretary_email },
                                    { title: 'General Secretary', person: club.general_secretary_name, email: club.general_secretary_email },
                                ].map((role, idx) => role.person && (
                                    <div key={idx} className="flex items-start gap-4 group">
                                        <div className="w-10 h-10 rounded-full flex items-center justify-center text-white shrink-0 bg-gradient-to-br from-white/5 to-white/10 border border-white/10">
                                            <User className="w-4 h-4 text-white/40 group-hover:text-white transition-colors" />
                                        </div>
                                        <div>
                                            <p className="text-xs font-bold uppercase tracking-wider text-white/30 mb-0.5">{role.title}</p>
                                            <p className="font-bold text-white/80 group-hover:text-white transition-colors">{role.person}</p>
                                            {role.email && <a href={`mailto:${role.email}`} className="text-xs text-[var(--primary)] hover:underline mt-0.5 block">{role.email}</a>}
                                        </div>
                                    </div>
                                ))}
                                {(!club.chair_name && !club.secretary_name) && (
                                    <p className="text-white/30 italic text-center py-4">Leadership information updating...</p>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

﻿'use client';

