                            opacity: 0.02,
                        }}
                        animate={{
                            rotate: [-15 + i * 8, -10 + i * 8],
                            opacity: [0.01, 0.04, 0.01],
                        }}
                        transition={{
                            duration: 15 + i * 2,
                            repeat: Infinity,
                            ease: "easeInOut",
                        }}
                    >
                        {text}
                    </motion.div>
                ))}
            </div>
        </div>
    );
};

