                        style={{
                            top: `${10 + i * 6}%`,
                            left: `${Math.random() * 40}%`,
                            right: `${Math.random() * 40}%`,
                            animationDelay: `${i * 0.3 + 0.5}s`,
                            animationDuration: `${3 + Math.random() * 2}s`,
                        }}
                    />
                ))}
            </div>
        </div>
    );
}

